        bool originalPanRoomWithMouseEdges = cameraManager.panRoomWithMouseEdges;
        bool originalZoomRoomWithMouseWheel = cameraManager.zoomRoomWithMouseWheel;

        // This navigation characterization deliberately owns the input lease for its duration.
        // Stop the still-running intro before the long multi-resolution probe so Story cannot
        // change that lease midway through a passage transition and invalidate the hover signal.
        InvokePrivateMethod(chapterManager, "StopChapterCoroutines");
        chapterManager.StopActiveDialogueForDebugTransition();
        player.SetInputEnabled(true);
        Assert.That(player.InputEnabled, Is.True);
        cameraManager.panRoomWithMouseEdges = false;
        cameraManager.zoomRoomWithMouseWheel = false;

        Vector2Int[] renderedSizes =
        {
            new Vector2Int(1366, 768),
            new Vector2Int(1440, 1080),
            new Vector2Int(1920, 1080),
            new Vector2Int(2560, 1080),
            new Vector2Int(2560, 1080)
        };
        Vector2[] requestedEntranceStarts =
        {
            new Vector2(-7.75f, -2.22f),
            new Vector2(0f, -2.2f),
            new Vector2(8.705841f, -2.346406f)
        };
        Vector2[] requestedRearStarts =
        {
            new Vector2(-7f, -2f),
            new Vector2(0f, -2f),
            new Vector2(7f, -2f)
        };
        List<string> profileLines = new List<string>(6);
        List<string> orderedEvents = new List<string>();
        List<Vector2> movementArrivals = new List<Vector2>();
        List<Vector2> movementStops = new List<Vector2>();
        System.Action recordArrival = () => movementArrivals.Add(player.LogicalPosition);
        System.Action recordMovementStop = () => movementStops.Add(player.LogicalPosition);
        UnityEngine.Events.UnityAction<string> recordRoomChanged = room => orderedEvents.Add(
            $"room-changed:{room}:" +
            (GetPrivateStaticField<AudioSource>(typeof(DoorTriggerNavigation), "activeNavigationAudioSource") ==
                passageAudioSource
                ? "audio-started"
                : "audio-idle"));
        player.ArrivedAtDestination += recordArrival;
        player.MovementStopped += recordMovementStop;
        navigation.OnCurrentRoomChanged.AddListener(recordRoomChanged);

        try
        {
            for (int profileIndex = 0; profileIndex < renderedSizes.Length; profileIndex++)
            {
                Vector2Int renderedSize = renderedSizes[profileIndex];
                bool maximumZoom = profileIndex == renderedSizes.Length - 1;
                yield return SetAndWaitForRenderedGameViewResolution(
                    (uint)renderedSize.x,
                    (uint)renderedSize.y);
                cameraManager.ResetRoomLookForPreview();
                yield return WaitForSettledLayout();
                if (maximumZoom)
                {
                    ApplyMaximumRoomZoom(cameraManager);
                    yield return WaitForSettledLayout();
                }
                Canvas.ForceUpdateCanvases();
                Physics2D.SyncTransforms();

                orderedEvents.Clear();
                movementArrivals.Clear();
                movementStops.Clear();
                List<string> laneObservations = new List<string>(3);
                for (int laneIndex = 0; laneIndex < requestedEntranceStarts.Length; laneIndex++)
                {
                    Assert.That(navigation.CurrentRoom, Is.EqualTo(EntranceRoom));
                    Assert.That(entranceContent.gameObject.activeInHierarchy, Is.True);
                    Assert.That(rearContent.gameObject.activeInHierarchy, Is.False);
                    Assert.That(player.TryWarpTo(requestedEntranceStarts[laneIndex], true), Is.True);
                    Vector2 entranceStart = player.LogicalPosition;
                    AssertFinite(entranceStart, $"profile {profileIndex} lane {laneIndex} Entrance start");
                    Assert.That(player.HasDestination, Is.False);
                    Vector2 bottomPoint = new Vector2(
                        renderedSize.x * (laneIndex == 0 ? 0.1f : laneIndex == 1 ? 0.5f : 0.9f),
                        14f);
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(bottomPoint), Is.True);
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(
                        new Vector2(bottomPoint.x, 29f)), Is.False);
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(
                        new Vector2(-1f, 14f)), Is.False);
                    if (profileIndex == 0 && laneIndex == 0)
                    {
                        forward.OnPointerEnter(null);
                        Assert.That(DoorTriggerNavigation.HoveredTrigger, Is.SameAs(forward));
                        Assert.That(passagePromptText.gameObject.activeSelf, Is.True);
                        Assert.That(passagePromptText.text, Is.EqualTo("Open Door"));
                    }

                    SetPrivateField(forward, "lastPointerActivationFrame", -1);
                    forward.ActivateDoor();
                    yield return WaitForSettledLayout();
                    Canvas.ForceUpdateCanvases();
                    Physics2D.SyncTransforms();
                    Assert.That(navigation.CurrentRoom, Is.EqualTo(RearDisplayName));
                    Assert.That(navigation.CurrentRoomDefinition, Is.SameAs(rearDefinition));
                    Assert.That(rearContent.gameObject.activeInHierarchy, Is.True);
                    Assert.That(entranceContent.gameObject.activeInHierarchy, Is.False);
                    Assert.That(player.HasDestination, Is.False);
                    Assert.That(player.InputEnabled, Is.True,
                        "The isolated navigation probe must retain its input lease.");
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(bottomPoint), Is.True);
                    Assert.That(DoorTriggerNavigation.HoveredTrigger, Is.SameAs(reverse),
                        "A retained bottom-edge pointer must automatically transfer to the active reciprocal exit.");
                    Assert.That(passagePromptText.gameObject.activeSelf, Is.True);
                    Assert.That(passagePromptText.text, Is.EqualTo("Open Door"));
                    Vector2 rearArrival = player.LogicalPosition;
                    Assert.That(TryMapLogicalPointToActiveRoomStageLocal(
                        player,
                        cameraManager,
                        rearArrival,
                        out Vector2 rearArrivalLocal), Is.True);
                    AssertFinite(rearArrival, $"profile {profileIndex} lane {laneIndex} rear arrival");
                    AssertFinite(rearArrivalLocal, $"profile {profileIndex} lane {laneIndex} rear local arrival");
                    AssertPassageArrivalResolverMatchesLegacyTrigger(
                        reverse,
                        player,
                        $"profile {profileIndex} lane {laneIndex} active rear arrival region");
                    InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");

                    Assert.That(player.TryWarpTo(requestedRearStarts[laneIndex], true), Is.True);
                    Vector2 rearStart = player.LogicalPosition;
                    AssertFinite(rearStart, $"profile {profileIndex} lane {laneIndex} rear start");
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(bottomPoint), Is.True);
                    SetPrivateField(reverse, "lastPointerActivationFrame", -1);
                    reverse.ActivateDoor();
                    yield return WaitForSettledLayout();
                    Canvas.ForceUpdateCanvases();
                    Physics2D.SyncTransforms();
                    Assert.That(navigation.CurrentRoom, Is.EqualTo(EntranceRoom));
                    Assert.That(navigation.CurrentRoomDefinition, Is.SameAs(entranceView.Definition));
                    Assert.That(entranceContent.gameObject.activeInHierarchy, Is.True);
                    Assert.That(rearContent.gameObject.activeInHierarchy, Is.False);
                    Assert.That(player.HasDestination, Is.False);
                    Assert.That(player.InputEnabled, Is.True,
                        "The isolated navigation probe must retain its input lease.");
                    Assert.That(DoorTriggerNavigation.IsPointerOverActiveTrigger(bottomPoint), Is.True);
                    Assert.That(DoorTriggerNavigation.HoveredTrigger, Is.SameAs(forward),
                        "Returning with a retained bottom-edge pointer must automatically transfer to the active reciprocal exit.");
                    Assert.That(passagePromptText.gameObject.activeSelf, Is.True);
                    Vector2 entranceArrival = player.LogicalPosition;
                    Assert.That(TryMapLogicalPointToActiveRoomStageLocal(
                        player,
                        cameraManager,
                        entranceArrival,
                        out Vector2 entranceArrivalLocal), Is.True);
                    AssertFinite(entranceArrival, $"profile {profileIndex} lane {laneIndex} Entrance arrival");
                    AssertFinite(entranceArrivalLocal,
                        $"profile {profileIndex} lane {laneIndex} Entrance local arrival");
                    AssertPassageArrivalResolverMatchesLegacyTrigger(
                        forward,
                        player,
                        $"profile {profileIndex} lane {laneIndex} active Entrance arrival region");
                    InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");

                    laneObservations.Add(
                        $"lane={laneIndex} entranceStart={FormatVector(entranceStart)} " +
                        $"rearArrival={FormatVector(rearArrival)} " +
                        $"rearArrivalLocal={FormatVector(rearArrivalLocal)} " +
                        $"rearStart={FormatVector(rearStart)} " +
                        $"entranceArrival={FormatVector(entranceArrival)} " +
                        $"entranceArrivalLocal={FormatVector(entranceArrivalLocal)}");
                }

                Assert.That(movementArrivals, Is.Empty,
                    "Bottom-edge passage activation must not create a movement-arrival event.");
                Assert.That(movementStops, Is.Empty,
                    "Bottom-edge passage activation must not create a movement-stop event.");
                Assert.That(orderedEvents, Is.EqualTo(new[]
                {
                    $"room-changed:{RearDisplayName}:audio-started",
                    $"room-changed:{EntranceRoom}:audio-started",
                    $"room-changed:{RearDisplayName}:audio-started",
                    $"room-changed:{EntranceRoom}:audio-started",
                    $"room-changed:{RearDisplayName}:audio-started",
                    $"room-changed:{EntranceRoom}:audio-started"
                }));
                string profileLine =
                    $"[GrandEntranceRearLegacyProfile] viewport={renderedSize.x}x{renderedSize.y} " +
                    $"zoom={(maximumZoom ? "maximum" : "default")} " +
                    $"events={string.Join("|", orderedEvents)} " +
                    string.Join(" | ", laneObservations);
                profileLines.Add(profileLine);
                Debug.Log(profileLine);
            }
        }
        finally
        {
            player.ArrivedAtDestination -= recordArrival;
            player.MovementStopped -= recordMovementStop;
            navigation.OnCurrentRoomChanged.RemoveListener(recordRoomChanged);
            InvokePrivateMethod(forward, "CancelPendingPlayerApproach");
            InvokePrivateMethod(reverse, "CancelPendingPlayerApproach");
            if (player.HasDestination)
            {
                InvokePrivateMethod(player, "CancelDestination");
            }
            InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");
            if (DoorTriggerNavigation.HoveredTrigger != null)
            {
                DoorTriggerNavigation.HoveredTrigger.OnPointerExit(null);
            }
            player.SetInputEnabled(originalInputEnabled);
            cameraManager.panRoomWithMouseEdges = originalPanRoomWithMouseEdges;
            cameraManager.zoomRoomWithMouseWheel = originalZoomRoomWithMouseWheel;
            cameraManager.ResetRoomLookForPreview();
            InvokePrivateMethod(cameraManager, "ApplyBackgroundLayout");
        }

        // Preserve the approved pre-authoring structure as immutable before-state evidence.
        // This sixth line intentionally describes the legacy graph and must not be rewritten
        // to describe the canonical graph now asserted independently below.
        string structuralLine =
            $"[GrandEntranceRearLegacyStructure] forwardGeometry={FormatVector(forwardRect.anchoredPosition)}/" +
            $"{FormatVector(forwardRect.sizeDelta)}/{FormatVector(new Vector2(forwardRect.localScale.x, forwardRect.localScale.y))} " +
            $"reverseGeometry={FormatVector(reverseRect.anchoredPosition)}/" +
            $"{FormatVector(reverseRect.sizeDelta)}/{FormatVector(new Vector2(reverseRect.localScale.x, reverseRect.localScale.y))} " +
            "bottomEdge=28 proximity=false walk=false callers=null serializedDependencies=null " +
            $"boundaries={entranceBoundary.GetPath(0).Length}/{rearBoundary.GetPath(0).Length} " +
            $"rails=2/2 alias={RearDisplayName}/{RearLegacyName} legacyCatalogIds=absent";
        profileLines.Add(structuralLine);
        Debug.Log(structuralLine);
        Assert.That(profileLines, Has.Count.EqualTo(6));
        string observationProfile = string.Join("\n", profileLines);
        Assert.That(observationProfile.EndsWith("\n", System.StringComparison.Ordinal), Is.False);
        string actualSha256 = ComputeSha256(observationProfile);
        Debug.Log($"[GrandEntranceRearLegacySha256] {actualSha256}");
        Assert.That(actualSha256, Is.EqualTo(ExpectedObservationSha256),
            "The reviewed six-line Group 10 before-state fingerprint must survive canonical authoring unchanged.");

        string canonicalStructureLine =
            "[GrandEntranceRearCanonicalStructure] roomViews=19 passages=38 callers=38/7 " +
            "sceneIds=4100000032/4100000033/4100000034 " +
            "definitions=64bc36c6e2d546d6bb878373c4e6d0b6/" +
            "aa8a2282356d4ad0aa3c9499a6f6f064/d57bc53c2dfb4a10bd63739d37028899 " +
            "stages=authored-anchors/authored-anchors modes=region/region " +
            "serializedDependencies=bound aliases=Grand Entrance Hall Rear View/Grand Entrance Hall Rear view " +
            "legacyCatalogIds=absent";
        Debug.Log(canonicalStructureLine);
        Assert.That(observationProfile, Does.Not.Contain("[GrandEntranceRearCanonicalStructure]"),
            "Current canonical structure evidence must remain outside the frozen legacy SHA input.");
    }

    [UnityTest]
    public IEnumerator GrandEntranceRearBilliardSourceRegionApproachResolverIsBitExactToLegacyAcrossRenderedAspects()
    {
        const string RearDisplayName = "Grand Entrance Hall Rear View";
        const string RearLegacyName = "Grand Entrance Hall Rear view";
        const string BilliardRoom = "Billiard Room";

        MainMenuController menu = RequireExactlyOneInActiveScene<MainMenuController>();
        menu.NewGame();
        yield return null;

        GameObject cursorChoice = GameObject.Find("Button_CursorStyle_01");
        Assert.That(cursorChoice, Is.Not.Null);
        Button cursorButton = cursorChoice.GetComponent<Button>();
        Assert.That(cursorButton, Is.Not.Null);
        cursorButton.onClick.Invoke();
        yield return SetAndWaitForRenderedGameViewResolution(1366, 768);

        RoomNavigationManager navigation = RequireExactlyOneInActiveScene<RoomNavigationManager>();
        PointClickPlayerMovement player = GameObject.Find("Player").GetComponent<PointClickPlayerMovement>();
        Assert.That(player, Is.Not.Null);
        CameraManager cameraManager = RequireExactlyOneInActiveScene<CameraManager>();
        ChapterManager chapterManager = RequireExactlyOneInActiveScene<ChapterManager>();
        DoorTriggerNavigation setupTrigger = null;
        DoorTriggerNavigation forward = null;
        DoorTriggerNavigation reverse = null;
        CanonicalPassage forwardPassage = null;
        CanonicalPassage reversePassage = null;
        CanonicalPassage originalForwardCaller = null;
        CanonicalPassage originalReverseCaller = null;
        Vector2 originalPlayerPosition = player.LogicalPosition;
        bool originalInputEnabled = player.InputEnabled;
        bool originalPanRoomWithMouseEdges = cameraManager.panRoomWithMouseEdges;
        bool originalZoomRoomWithMouseWheel = cameraManager.zoomRoomWithMouseWheel;

        InvokePrivateMethod(chapterManager, "StopChapterCoroutines");
        chapterManager.StopActiveDialogueForDebugTransition();
        player.SetInputEnabled(true);
        cameraManager.panRoomWithMouseEdges = false;
        cameraManager.zoomRoomWithMouseWheel = false;

        try
        {
            cameraManager.ResetRoomLookForPreview();
            yield return WaitForSettledLayout();

            setupTrigger = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_GEH_toRearView");
            SetPrivateField(setupTrigger, "lastPointerActivationFrame", -1);
            setupTrigger.ActivateDoor();
            yield return WaitForSettledLayout();
            Assert.That(navigation.CurrentRoom, Is.EqualTo(RearDisplayName));
            originalPlayerPosition = player.LogicalPosition;
            InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");

            forward = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_GEH_Rear_BilliardRoom");
            reverse = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_BilliardRoom_GEH");
            Assert.That(forward.GetComponents<Component>(), Has.Length.EqualTo(5));
            Assert.That(reverse.GetComponents<Component>(), Has.Length.EqualTo(5));
            forwardPassage = forward.GetComponent<CanonicalPassage>();
            reversePassage = reverse.GetComponent<CanonicalPassage>();
            Assert.That(forwardPassage, Is.Not.Null);
            Assert.That(reversePassage, Is.Not.Null);
            Assert.That(forward.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
            Assert.That(reverse.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
            originalForwardCaller = GetPrivateField<CanonicalPassage>(forward, "canonicalPassage");
            originalReverseCaller = GetPrivateField<CanonicalPassage>(reverse, "canonicalPassage");
            Assert.That(originalForwardCaller, Is.SameAs(forwardPassage));
            Assert.That(originalReverseCaller, Is.SameAs(reversePassage));

            RectTransform forwardRect = forward.transform as RectTransform;
            RectTransform reverseRect = reverse.transform as RectTransform;
            Assert.That(forwardRect, Is.Not.Null);
            Assert.That(reverseRect, Is.Not.Null);
            CanonicalRoomView rearRoomView = forward.GetComponentInParent<CanonicalRoomView>(true);
            CanonicalRoomView billiardRoomView = reverse.GetComponentInParent<CanonicalRoomView>(true);
            Assert.That(rearRoomView, Is.Not.Null);
            Assert.That(billiardRoomView, Is.Not.Null);
            Assert.That(rearRoomView.LegacyContentGroup.RoomName, Is.EqualTo(RearLegacyName));
            Assert.That(billiardRoomView.LegacyContentGroup.RoomName, Is.EqualTo(BilliardRoom));

            AssertCanonicalSourceAndArrivalRegionPassage(
                forwardPassage,
                forwardPassage.Definition,
                rearRoomView,
                reversePassage,
                new Vector2(-745.00006f, -114.72981f),
                new Vector2(-745.00006f, 238.13548f),
                new Vector2(-501.32404f, 238.13548f),
                new Vector2(-501.32404f, -114.72981f),
                "Rear-to-Billiard production Passage");
            AssertCanonicalSourceAndArrivalRegionPassage(
                reversePassage,
                reversePassage.Definition,
                billiardRoomView,
                forwardPassage,
                new Vector2(579.6167f, -250.84499f),
                new Vector2(579.6167f, 31.911606f),
                new Vector2(702.0674f, 31.911606f),
                new Vector2(702.0674f, -250.84499f),
                "Billiard-to-Rear production Passage");

            Vector2Int[] renderedSizes =
            {
                new Vector2Int(1366, 768),
                new Vector2Int(1440, 1080),
                new Vector2Int(1920, 1080),
                new Vector2Int(2560, 1080),
                new Vector2Int(2560, 1080)
            };
            Vector2[] forwardRequestedStarts =
            {
                new Vector2(0f, -2f),
                new Vector2(-4f, -2f),
                new Vector2(-2f, -3f),
                new Vector2(2f, -2f),
                new Vector2(0f, -3f)
            };
            Vector2[] reverseRequestedStarts =
            {
                new Vector2(0f, -2f),
                new Vector2(4f, -2f),
                new Vector2(2f, -3f),
                new Vector2(-2f, -2f),
                new Vector2(0f, -3f)
            };

            for (int profileIndex = 0; profileIndex < renderedSizes.Length; profileIndex++)
            {
                Vector2Int renderedSize = renderedSizes[profileIndex];
                bool maximumZoom = profileIndex == renderedSizes.Length - 1;
                string profileLabel =
                    $"{renderedSize.x}x{renderedSize.y}-{(maximumZoom ? "maximum" : "default")}";
                yield return SetAndWaitForRenderedGameViewResolution(
                    (uint)renderedSize.x,
                    (uint)renderedSize.y);
                cameraManager.ResetRoomLookForPreview();
                yield return WaitForSettledLayout();
                if (maximumZoom)
                {
                    ApplyMaximumRoomZoom(cameraManager);
                    yield return WaitForSettledLayout();
                }
                Canvas.ForceUpdateCanvases();

                Assert.That(navigation.CurrentRoom, Is.EqualTo(RearDisplayName));
                AssertSourceRegionApproachParityFromTwoFarStarts(
                    forward,
                    forwardPassage,
                    player,
                    cameraManager,
                    navigation,
                    forwardRequestedStarts,
                    $"{profileLabel} Rear-to-Billiard",
                    proveMismatchFailsClosed: profileIndex == 0);

                Assert.That(navigation.MoveThroughInspectorDoor(
                    forward.SourceRoom,
                    forward.DoorName,
                    forward.DestinationRoom,
                    true), Is.True);
                yield return WaitForSettledLayout();
                Assert.That(navigation.CurrentRoom, Is.EqualTo(BilliardRoom));
                cameraManager.ResetRoomLookForPreview();
                yield return WaitForSettledLayout();
                if (maximumZoom)
                {
                    ApplyMaximumRoomZoom(cameraManager);
                    yield return WaitForSettledLayout();
                }
                Canvas.ForceUpdateCanvases();

                AssertSourceRegionApproachParityFromTwoFarStarts(
                    reverse,
                    reversePassage,
                    player,
                    cameraManager,
                    navigation,
                    reverseRequestedStarts,
                    $"{profileLabel} Billiard-to-Rear",
                    proveMismatchFailsClosed: profileIndex == 0);

                Assert.That(navigation.MoveThroughInspectorDoor(
                    reverse.SourceRoom,
                    reverse.DoorName,
                    reverse.DestinationRoom,
                    true), Is.True);
                yield return WaitForSettledLayout();
                Assert.That(navigation.CurrentRoom, Is.EqualTo(RearDisplayName));
                InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");
            }
        }
        finally
        {
            if (forward != null)
            {
                InvokePrivateMethod(forward, "CancelPendingPlayerApproach");
            }
            if (reverse != null)
            {
                InvokePrivateMethod(reverse, "CancelPendingPlayerApproach");
            }
            if (setupTrigger != null)
            {
                InvokePrivateMethod(setupTrigger, "CancelPendingPlayerApproach");
            }
            if (player.HasDestination)
            {
                InvokePrivateMethod(player, "CancelDestination");
            }
            InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");
            if (DoorTriggerNavigation.HoveredTrigger != null)
            {
                DoorTriggerNavigation.HoveredTrigger.OnPointerExit(null);
            }
            if (navigation.CurrentRoom == BilliardRoom && reverse != null)
            {
                navigation.MoveThroughInspectorDoor(
                    reverse.SourceRoom,
                    reverse.DoorName,
                    reverse.DestinationRoom,
                    true);
            }
            if (navigation.CurrentRoom == RearDisplayName)
            {
                player.TryWarpTo(originalPlayerPosition, true);
            }
            player.SetInputEnabled(originalInputEnabled);
            cameraManager.panRoomWithMouseEdges = originalPanRoomWithMouseEdges;
            cameraManager.zoomRoomWithMouseWheel = originalZoomRoomWithMouseWheel;
            cameraManager.ResetRoomLookForPreview();
            InvokePrivateMethod(cameraManager, "ApplyBackgroundLayout");
        }

        Assert.That(forward.GetComponents<Component>(), Has.Length.EqualTo(5));
        Assert.That(reverse.GetComponents<Component>(), Has.Length.EqualTo(5));
        Assert.That(forward.GetComponent<CanonicalPassage>(), Is.SameAs(forwardPassage));
        Assert.That(reverse.GetComponent<CanonicalPassage>(), Is.SameAs(reversePassage));
        Assert.That(forward.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
        Assert.That(reverse.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
        Assert.That(GetPrivateField<CanonicalPassage>(forward, "canonicalPassage"),
            Is.SameAs(originalForwardCaller));
        Assert.That(GetPrivateField<CanonicalPassage>(reverse, "canonicalPassage"),
            Is.SameAs(originalReverseCaller));
    }

    [UnityTest]
    public IEnumerator GrandEntranceRearBilliardLegacyPassagesAndCatalogConflictAreCharacterizedAcrossRenderedAspects()
    {
        const string RearDisplayName = "Grand Entrance Hall Rear View";
        const string RearLegacyName = "Grand Entrance Hall Rear view";
        const string BilliardRoom = "Billiard Room";
        const string ExpectedObservationSha256 =
            "56e7cc4b59801f8dfb9da547ff584f7b184bea0d15398e7a0b31f85b83b1b39b";

        MainMenuController menu = RequireExactlyOneInActiveScene<MainMenuController>();
        menu.NewGame();
        yield return null;

        GameObject cursorChoice = GameObject.Find("Button_CursorStyle_01");
        Assert.That(cursorChoice, Is.Not.Null);
        Button cursorButton = cursorChoice.GetComponent<Button>();
        Assert.That(cursorButton, Is.Not.Null);
        cursorButton.onClick.Invoke();
        yield return SetAndWaitForRenderedGameViewResolution(1366, 768);

        RoomNavigationManager navigation = RequireExactlyOneInActiveScene<RoomNavigationManager>();
        PointClickPlayerMovement player = GameObject.Find("Player").GetComponent<PointClickPlayerMovement>();
        Assert.That(player, Is.Not.Null);
        CameraManager cameraManager = RequireExactlyOneInActiveScene<CameraManager>();
        ChapterManager chapterManager = RequireExactlyOneInActiveScene<ChapterManager>();
        DoorTriggerNavigation setupTrigger = null;
        DoorTriggerNavigation forward = null;
        DoorTriggerNavigation reverse = null;
        bool originalInputEnabled = player.InputEnabled;
        float originalMoveSpeed = GetPrivateValue<float>(player, "moveSpeed");
        bool originalPanRoomWithMouseEdges = cameraManager.panRoomWithMouseEdges;
        bool originalZoomRoomWithMouseWheel = cameraManager.zoomRoomWithMouseWheel;
        List<string> profileLines = new List<string>(6);

        InvokePrivateMethod(chapterManager, "StopChapterCoroutines");
        chapterManager.StopActiveDialogueForDebugTransition();
        player.SetInputEnabled(true);
        SetPrivateField(player, "moveSpeed", 1000f);
        cameraManager.panRoomWithMouseEdges = false;
        cameraManager.zoomRoomWithMouseWheel = false;

        try
        {
            cameraManager.ResetRoomLookForPreview();
            yield return WaitForSettledLayout();

            setupTrigger = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_GEH_toRearView");
            CanonicalPassage setupPassage = setupTrigger.GetComponent<CanonicalPassage>();
            Assert.That(setupPassage, Is.Not.Null,
                "Group11 setup must reuse the accepted Entrance-to-Rear canonical Passage.");
            Assert.That(setupPassage.ArrivalPlacementMode,
                Is.EqualTo(PassageArrivalPlacementMode.BestReachableInAuthoredRegion));
            SetPrivateField(setupTrigger, "lastPointerActivationFrame", -1);
            setupTrigger.ActivateDoor();
            yield return WaitForSettledLayout();
            Assert.That(navigation.CurrentRoom, Is.EqualTo(RearDisplayName));
            InvokePrivateStaticMethod(typeof(DoorTriggerNavigation), "StopCurrentNavigationSound");

            forward = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_GEH_Rear_BilliardRoom");
            reverse = RequireSceneObject<DoorTriggerNavigation>("DoorTrigger_BilliardRoom_GEH");
            Assert.That(forward.gameObject.name, Is.EqualTo("DoorTrigger_GEH_Rear_BilliardRoom"));
            Assert.That(reverse.gameObject.name, Is.EqualTo("DoorTrigger_BilliardRoom_GEH"));
            Assert.That(forward.GetComponents<Component>(), Has.Length.EqualTo(5));
            Assert.That(reverse.GetComponents<Component>(), Has.Length.EqualTo(5));
            CanonicalPassage forwardPassage = forward.GetComponent<CanonicalPassage>();
            CanonicalPassage reversePassage = reverse.GetComponent<CanonicalPassage>();
            Assert.That(forwardPassage, Is.Not.Null);
            Assert.That(reversePassage, Is.Not.Null);
            Assert.That(forward.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
            Assert.That(reverse.GetComponents<CanonicalPassage>(), Has.Length.EqualTo(1));
