    {
        Assert.That(passage.Definition, Is.SameAs(expectedDefinition), $"{label} definition changed.");
        Assert.That(passage.SourceRoomView, Is.SameAs(expectedSourceRoomView),
            $"{label} source RoomView changed.");
        Assert.That(passage.ReversePassage, Is.SameAs(expectedReverse),
            $"{label} reciprocal link changed.");
        Assert.That(passage.AnchorMigrationStage, Is.EqualTo(PassageAnchorMigrationStage.AuthoredAnchors));
        Assert.That(passage.HasValidAnchorMigrationStage, Is.True);
        Assert.That(passage.UsesAuthoredApproach, Is.True);
        Assert.That(passage.ArrivalPlacementMode,
            Is.EqualTo(PassageArrivalPlacementMode.BestReachableInAuthoredRegion));
        Assert.That(passage.HasValidArrivalPlacementMode, Is.True);
        Assert.That(passage.UsesBestReachableArrivalRegion, Is.True);
        Assert.That(passage.ApproachAnchor, Is.Not.Null);
        Assert.That(passage.ApproachAnchor.CoordinateSpace,
            Is.EqualTo(PassageAnchorCoordinateSpace.RoomViewLocal));
        Assert.That(passage.ApproachAnchor.LogicalPosition, Is.EqualTo(Vector2.zero));
        AssertVector2Within(
            passage.ApproachAnchor.RoomViewLocalPosition,
            expectedApproach,
            0.0001f,
            $"{label} approach");
        Assert.That(passage.ArrivalAnchor, Is.Not.Null,
            $"{label} may receive Unity's default missing-field object at runtime.");
        Assert.That(passage.ArrivalAnchor.LogicalPosition, Is.EqualTo(Vector2.zero));
        Assert.That(passage.ArrivalAnchor.RoomViewLocalPosition, Is.EqualTo(Vector2.zero));

        PassageArrivalRegionData region = passage.ArrivalRegion;
        Assert.That(region, Is.Not.Null);
        Assert.That(region.HasValidRoomViewLocalCorners, Is.True);
        AssertVector2Within(region.BottomLeft, expectedBottomLeft, 0.0001f, $"{label} bottom-left");
        AssertVector2Within(region.TopLeft, expectedTopLeft, 0.0001f, $"{label} top-left");
        AssertVector2Within(region.TopRight, expectedTopRight, 0.0001f, $"{label} top-right");
        AssertVector2Within(region.BottomRight, expectedBottomRight, 0.0001f, $"{label} bottom-right");

        Chateau.Architecture.ValidationReport report = new Chateau.Architecture.ValidationReport();
        passage.ValidateConfiguration(report);
        Assert.That(report.HasErrors, Is.False, $"{label} must pass canonical configuration validation.");
    }

    private static void AssertPassageArrivalResolverMatchesLegacyTrigger(
        DoorTriggerNavigation activeTrigger,
        PointClickPlayerMovement player,
        string label)
    {
        Assert.That(activeTrigger, Is.Not.Null, $"{label}: active trigger is required.");
        Assert.That(activeTrigger.isActiveAndEnabled, Is.True,
            $"{label}: parity must use the destination room's active trigger.");
        Assert.That(player, Is.Not.Null, $"{label}: Player is required.");
        Assert.That(player.HasDestination, Is.False,
            $"{label}: parity must sample the same settled player state.");

        RectTransform triggerRect = activeTrigger.transform as RectTransform;
        Assert.That(triggerRect, Is.Not.Null, $"{label}: trigger requires its RectTransform region.");
        Vector3[] worldCorners = new Vector3[4];
        triggerRect.GetWorldCorners(worldCorners);
        Canvas canvas = activeTrigger.GetComponentInParent<Canvas>();
        Camera canvasCamera = canvas == null || canvas.renderMode == RenderMode.ScreenSpaceOverlay
            ? null
            : canvas.worldCamera;
        PassageArrivalRuntimeRegion runtimeRegion = new PassageArrivalRuntimeRegion(
            CreatePassageArrivalRegionCorner(worldCorners[0], canvasCamera),
            CreatePassageArrivalRegionCorner(worldCorners[1], canvasCamera),
            CreatePassageArrivalRegionCorner(worldCorners[2], canvasCamera),
            CreatePassageArrivalRegionCorner(worldCorners[3], canvasCamera));
        Assert.That(runtimeRegion.TryGetScreenBounds(out _, out _), Is.True,
            $"{label}: trigger corners must form one finite rendered region.");
        Assert.That(player.TryGetScreenPointFromLogicalPosition(
            player.LogicalPosition,
            out Vector2 playerScreenPosition), Is.True,
            $"{label}: Player logical position must project into the active room.");

        bool legacyResolved = activeTrigger.TryFindArrivalDestination(
            player,
            out Vector2 legacyDestination);
        bool canonicalResolved = PassageArrivalResolver.TryResolveBestReachableDestination(
            runtimeRegion,
            playerScreenPosition,
            player,
            out Vector2 canonicalDestination);
        Assert.That(canonicalResolved, Is.EqualTo(legacyResolved),
            $"{label}: canonical and delegating legacy resolution success must match.");
        Assert.That(legacyResolved, Is.True,
            $"{label}: the characterized destination region must remain reachable.");
        AssertVector2Within(
            canonicalDestination,
            legacyDestination,
            0.0001f,
            $"{label} canonical/legacy destination parity");
        Assert.That(player.HasDestination, Is.False,
            $"{label}: arrival queries must not dispatch movement.");
    }

    private static PassageArrivalRegionCorner CreatePassageArrivalRegionCorner(
        Vector3 worldPosition,
        Camera canvasCamera)
    {
        return new PassageArrivalRegionCorner(
            worldPosition,
            RectTransformUtility.WorldToScreenPoint(canvasCamera, worldPosition));
    }

    private static IEnumerator WaitForSettledLayout()
    {
        for (int frame = 0; frame < 4; frame++)
        {
            Canvas.ForceUpdateCanvases();
            yield return null;
        }
    }

    private static void AssertDoorTriggerCompatibilityBindings(
        DoorTriggerNavigation outbound,
        DoorTriggerNavigation reverse,
        RoomNavigationManager navigation,
        Transform playerTransform,
        AudioSource passageAudioSource,
        DoorOpenSoundCatalog passageDoorCatalog)
    {
        Assert.That(passageDoorCatalog, Is.Not.Null);
        Assert.That(
            AssetDatabase.GetAssetPath(passageDoorCatalog),
            Is.EqualTo("Assets/Resources/Audio/DoorOpenSoundCatalog.asset"));

        DoorTriggerNavigation[] triggers = { outbound, reverse };
        for (int i = 0; i < triggers.Length; i++)
        {
            DoorTriggerNavigation trigger = triggers[i];
            Assert.That(GetPrivateField<RoomNavigationManager>(trigger, "navigationManager"), Is.SameAs(navigation));
            Assert.That(GetPrivateField<Transform>(trigger, "player"), Is.SameAs(playerTransform));
            Assert.That(GetPrivateField<AudioSource>(trigger, "doorOpenAudioSource"), Is.SameAs(passageAudioSource));
            Assert.That(GetPrivateField<DoorOpenSoundCatalog>(trigger, "doorOpenSoundCatalog"), Is.SameAs(passageDoorCatalog));
        }
    }

    private static IEnumerator SetAndWaitForRenderedGameViewResolution(uint width, uint height)
    {
        PlayModeWindow.SetViewType(PlayModeWindow.PlayModeViewTypes.GameView);
        PlayModeWindow.SetCustomRenderingResolution(width, height, CharacterizationGameViewSizeName);

        for (int frame = 0; frame < 16; frame++)
        {
            Canvas.ForceUpdateCanvases();
            yield return null;

            PlayModeWindow.GetRenderingResolution(out uint actualWidth, out uint actualHeight);
            if (actualWidth == width &&
                actualHeight == height &&
                Screen.width == (int)width &&
                Screen.height == (int)height)
            {
                yield return WaitForSettledLayout();
                yield break;
            }
        }

        PlayModeWindow.GetRenderingResolution(out uint finalWidth, out uint finalHeight);
        Assert.Fail(
            $"Rendered Game view did not settle at {width}x{height}; " +
            $"editor={finalWidth}x{finalHeight}, runtime={Screen.width}x{Screen.height}.");
    }

    private static void AssertChapterIntroGraphRemainsStable(
        ChapterIntroUI intro,
