            0.0001f,
            "passive forward arrival anchor");
        AssertVector2Within(
            reversePassage.ApproachAnchor.LogicalPosition,
            new Vector2(5.267176f, -2.104616f),
            0.0001f,
            "passive reverse approach anchor");
        AssertVector2Within(
